const body = $input.first().json.body || {};

const message = body?.entry?.[0]?.changes?.[0]?.value?.messages?.[0];
const value   = body?.entry?.[0]?.changes?.[0]?.value;

// Ignorer si pas de message
if (!message) return [];

const from = message.from;
const name = value?.contacts?.[0]?.profile?.name || ('+' + from);
const ts   = new Date(parseInt(message.timestamp) * 1000)
  .toLocaleString('fr-FR', {
    timeZone: 'Africa/Lome',
    day: '2-digit', month: '2-digit', year: 'numeric',
    hour: '2-digit', minute: '2-digit'
  });

const typeMap = {
  text:     () => message.text?.body || '',
  image:    () => '[Image]',
  audio:    () => '[Message vocal]',
  video:    () => '[Vidéo]',
  document: () => '[Document]',
  sticker:  () => '[Sticker]',
};
const texte = (typeMap[message.type] || (() => `[${message.type}]`))();
const texteLower = texte.toLowerCase();

// ── Réponse automatique selon mots-clés ─────────────────
let reponse = '';

if (/commande|numéro|numero|cmd/.test(texteLower)) {
  reponse =
    `Bonjour ${name} 👋\n\n` +
    `Merci pour votre message concernant votre commande.\n\n` +
    `Notre équipe vérifie votre dossier et vous répond très rapidement. ` +
    `Si vous avez votre numéro de commande (ex: CMD-...), n'hésitez pas à le partager pour accélérer le traitement.\n\n` +
    `À très vite ! 🙏\n— *TOGOLESE*`;

} else if (/livraison|délai|delai|expédition|expedition|arrivée|arrivee|quand/.test(texteLower)) {
  reponse =
    `Bonjour ${name} 👋\n\n` +
    `Concernant les délais de livraison :\n\n` +
    `✈️ *EXPRESS (avion)* : 4 à 14 jours\n` +
    `🚢 *ECO (bateau)* : 30 à 45 jours\n\n` +
    `Dès que votre colis arrive, vous recevrez une notification. ` +
    `Pour plus d'informations, notre équipe est disponible.\n\n` +
    `— *TOGOLESE*`;

} else if (/prix|tarif|coût|cout|combien|payer|paiement|acompte/.test(texteLower)) {
  reponse =
    `Bonjour ${name} 👋\n\n` +
    `Merci pour votre intérêt ! 😊\n\n` +
    `Pour toute question tarifaire ou concernant votre paiement, ` +
    `notre équipe vous répondra dans les plus brefs délais.\n\n` +
    `— *TOGOLESE*`;

} else if (/merci|thank|super|parfait|ok|reçu|recu|bien reçu/.test(texteLower)) {
  reponse =
    `Merci à vous ${name} ! 🙏\n\n` +
    `C'est toujours un plaisir de vous servir. ` +
    `N'hésitez pas à nous contacter pour toute question.\n\n` +
    `— *TOGOLESE*`;

} else {
  reponse =
    `Bonjour ${name} 👋\n\n` +
    `Merci pour votre message, nous l'avons bien reçu ! ✅\n\n` +
    `Notre équipe vous répondra dans les plus brefs délais.\n\n` +
    `Pour toute urgence, vous pouvez nous appeler directement au *+228 90 22 64 91*.\n\n` +
    `— *TOGOLESE*`;
}

// Notification Kent
const notifKent =
  `📩 *Réponse client*\n` +
  `👤 *${name}*  |  📞 +${from}\n` +
  `🕐 ${ts}\n\n` +
  `💬 ${texte}`;

return [{ json: { from, name, texte, reponse, notifKent } }];
